plugins {
    id 'com.android.application'
    id 'org.jetbrains.kotlin.android'
}

android {
    namespace 'com.gpt.auto.reader'
    compileSdk 34

    defaultConfig {
        applicationId "com.gpt.auto.reader"
        minSdk 24
        targetSdk 34
        versionCode 1
        versionName "1.0"

        // Limit to 64-bit ARM to save 50% of APK size
        ndk {
            abiFilters "arm64-v8a"
        }
    }

    buildFeatures {
        compose true
    }

    composeOptions {
        kotlinCompilerExtensionVersion '1.5.14'
    }

    buildTypes {
        release {
            minifyEnabled true
            shrinkResources true
            proguardFiles getDefaultProguardFile('proguard-android-optimize.txt'), 'proguard-rules.pro'
        }
        debug {
            // Debug is now minified to keep size small during testing
