            setOnErrorListener { _, what, extra ->
                val err = when(what) {
                    MediaPlayer.MEDIA_ERROR_UNKNOWN -> "UNKNOWN"
                    MediaPlayer.MEDIA_ERROR_SERVER_DIED -> "SERVER_DIED"
                    else -> "WHAT_$what"
                }
                val det = when(extra) {
